#import "PLXPPollingOptBleLocationHandler.h"
#import "PLXPPollingOptPredictModel.h"
#import "PLXPUtility.h"
#import "PLXPAppStartTool.h"

static BOOL g_firstReceiveRssi = YES;

@interface PLXPPollingOptBleLocationHandler()

@end

@implementation PLXPPollingOptBleLocationHandler

- (instancetype)init {
    if (self = [super init]) {
    }
    return self;
}

- (void)dealloc {
}

- (void)initBleLocationWithPredictConfig:(PLPredictConfig * _Nullable)config otaConfig:(NSArray *)otaConfig {
    self.predictModel = [[PLXPPollingOptPredictModel alloc] initWithPredictConfig:config pollingConfigs:otaConfig];
}

- (void)setStartDistance:(float)startDistance {
    PLXPPollingOptPredictModel *predictModel = (PLXPPollingOptPredictModel *)self.predictModel;
    predictModel.startDistance = startDistance;
}

- (void)rssiManagerDidReceiveRssiArray:(NSArray<PLXPRssiModel *> *)rssiArray {
    if (rssiArray.count > 0) {
        if (g_firstReceiveRssi)
        {
            NSTimeInterval currentTime = [PLXPUtility dateTimestamp];
            DLogTagInfo(kStatisticsReportTag, @"App启动-第一次返回rssi耗时（%.03f秒）", (currentTime - [PLXPAppStartTool getAppStartTime]) / 1000.0);
            g_firstReceiveRssi = NO;
        }
        std::vector<ble_rssi> rssiV;
        for (PLXPRssiModel *model in rssiArray) {
            ble_rssi rssi;
            rssi.rssi = model.rssi;
            rssi.name = [model.name UTF8String];
            rssiV.push_back(rssi);
        }
        PLXPPollingOptPredictModel *predictModel = (PLXPPollingOptPredictModel *)self.predictModel;
        [predictModel predictWithRssi:rssiV];
    }
}

#pragma mark — XPBleLocationHandlerProtocol
- (void)detectBleConnect:(BOOL)inBluetoothSession {
    if (!inBluetoothSession) {
        DLogTagInfo(kBLEKeyPredictTag, @"重连不成功，重置model");
        [self.predictModel reset];
    }
}

@end

