   191→- (PLBLEKeyDistanceLevel)location {
   192→    if (model == NULL) {
   193→        return PLBLEKeyDistanceLevelInitCircle;
   194→    }
   195→    if (decisionPower.size() > 0) {
   196→        decision_distance_config *suitDistanceConfig = NULL;
   197→        int suitIndex = -1;
   198→        for (int i = 0;i<decisionPower.size();i++) {
   199→            decision_power &power = decisionPower[i];
   200→            decision_distance_config &decisionConfig = decisionDistances[i];
   201→            if (power.lessCount >= decisionConfig.lessPower) {
   202→                suitIndex = i;
   203→                suitDistanceConfig = &decisionConfig;
   204→                break;
   205→            }
   206→        }
   207→        DLogTagDebug(kBLEKeyPredictTag, @"找到了满足的index:%d",suitIndex);
   208→        if (suitIndex != -1) {
   209→            if (self.distanceLevel == PLBLEKeyDistanceLevelInitCircle || suitIndex == 0) {
   210→                self.distanceLevel = suitDistanceConfig->lessLevel;
   211→            } else {
   212→                decision_distance_config *moreDistanceConfig = NULL;
   213→                for (int i = suitIndex-1;i>=0;i--) {
   214→                    decision_power &power = decisionPower[i];
   215→                    decision_distance_config &decisionConfig = decisionDistances[i];
   216→                    if (power.moreCount >= decisionConfig.morePower) {
   217→                        DLogTagDebug(kBLEKeyPredictTag, @"找到了满足的配置:%f,%d",decisionConfig.distance,decisionConfig.morePower);
   218→                        moreDistanceConfig = &decisionConfig;
   219→                        break;
   220→                    }
   221→                }
   222→                if (suitDistanceConfig != NULL && moreDistanceConfig != NULL) {
   223→                    if (self.distanceLevel <= moreDistanceConfig->moreLevel) {
   224→                        self.distanceLevel = moreDistanceConfig->moreLevel;
   225→                    } else {
   226→                        self.distanceLevel = suitDistanceConfig->lessLevel;
   227→                    }
   228→                }
   229→                    
   230→            }
   231→        }
   232→    }
   233→    return self.distanceLevel;
   234→}
