   418→- (void)predictWithRssi:(std::vector<ble_rssi> &)rssiV {
   419→    if (model == NULL) {
   420→#ifdef XPPollingSDK_Test_Mode
   421→        printf("%s", [@"PLXPPollingOptPredictModel model为空，不执行定位" cStringUsingEncoding:NSUTF8StringEncoding]);
   422→#endif  //XPPollingSDK_Test_Mode
   423→        DLogTagWarn(kBLEKeyPredictTag, @"model为空，不执行定位");
   424→        return;
   425→    }
   426→    std::vector<std::vector<float>> input;
   427→    PLXPPollingPredictInterfaceOpt *predictModel = (PLXPPollingPredictInterfaceOpt *)model;
   428→    predictModel->preprocess(rssiV, input);
   429→    if (input.empty()) {
   430→        DLogTagDebug(kBLEKeyPredictTag, @"model为空，不执行定位");
   431→        return;
   432→    }
   433→    DLogTagDebug(@"input", @"%@",[self printInput:input]);
   434→    std::vector<on_time_distance> output;
   435→    predictModel->inference(output);
   436→    if (output.empty() || output.size() == 0) {
   437→#ifdef XPPollingSDK_Test_Mode
   438→        printf("%s", [@"predictClass fail!" cStringUsingEncoding:NSUTF8StringEncoding]);
   439→#endif  //XPPollingSDK_Test_Mode
   440→        DLogTagError(kBLEKeyPredictTag, @"predictClass fail!");
   441→        return;
   442→    }
   443→    
   444→    std::vector<on_time_distance> outCarDistances;
   445→    std::vector<on_time_distance> communicateDistances;
   446→    float isCommunicateDistance = 0;
   447→    float inCarDistance = 0;
   448→    for(int i = 0;i<output.size();i++) {
   449→        on_time_distance &distance = output[i];
   450→        if (distance.is_communicate) {
   451→            if (distance.distance != PLINVAILD_DISTANCE) {
   452→                isCommunicateDistance += distance.distance;
   453→                communicateDistances.push_back(distance);
   454→            }
   455→        } else {
   456→            if (distance.distance != PLINVAILD_DISTANCE) {
   457→                outCarDistances.push_back(distance);
   458→            }
   459→        }
   460→    }
   461→    
   462→    isCommunicateDistance = isCommunicateDistance / communicateDistances.size();
   463→    
   464→    float currentDistance = 0;
   465→    if (isCommunicateDistance <= PLMUST_UNLOCK_DISTANCE/2.0) {
   466→        currentDistance = isCommunicateDistance;
   467→    } else {
   468→        std::sort(outCarDistances.begin(), outCarDistances.end(), plCompareOnTimeDistanceFunction);
   469→        if (outCarDistances.size() > 0) {
   470→            float outDistance = outCarDistances.front().distance;
   471→            float reveatDistance = (outDistance + isCommunicateDistance)/2;
   472→            if (reveatDistance < PLSAFE_DISTANCE) {
   473→                currentDistance = reveatDistance;
   474→            } else {
   475→                if (outDistance < isCommunicateDistance) {
   476→                    currentDistance = outDistance * self.predictConfig.slaveStrongerRate + isCommunicateDistance * (1-self.predictConfig.slaveStrongerRate);
   477→                } else {
   478→                    if (isCommunicateDistance <= _bussinessDistance.unlockDistance) {
   479→                        if (outDistance > isCommunicateDistance * 2) {
   480→                            currentDistance = isCommunicateDistance * PLREVEAL_RATE + outDistance * (1-PLREVEAL_RATE);
   481→                        } else {
   482→                            currentDistance = isCommunicateDistance * self.predictConfig.mainStrongerRate + outDistance * (1-self.predictConfig.mainStrongerRate);
   483→                        }
   484→                    } else {
   485→                        currentDistance = isCommunicateDistance * self.predictConfig.mainStrongerRate + outDistance * (1-self.predictConfig.mainStrongerRate);
   486→                    }
   487→                }
   488→            }
   489→        } else {
   490→            currentDistance = isCommunicateDistance;
   491→        }
   492→    }
   493→    DLogTagDebug(kBLEKeyPredictTag, @"加权后的距离是:%.2f",currentDistance);
   494→    
   495→    if (distancePower.size() > 0) {
   496→        std::vector<float> lastCredictDistance = [self getLastCredictDistance];
   497→        int credictCount = (int)lastCredictDistance.size();
   498→        float historyDistance = 0;
   499→        for (int i = 0;i<credictCount;i++) {
   500→            if (lastCredictDistance[i] != PLINVAILD_DISTANCE) {
   501→                historyDistance += lastCredictDistance[i] * PLHISTORY_RATE * [self getLineWeight:i+1 size:credictCount];
   502→            }
   503→        }
   504→        currentDistance = currentDistance * PLCURRENT_RATE + historyDistance;
   505→    }
   506→    
   507→    for (int i = 0;i<decisionDistances.size();i++) {
   508→        if (currentDistance <= decisionDistances[i].distance) {
   509→            [self stasticsCurrentDistanceCount:decisionDistances[i].distance];
   510→            break;
   511→        }
   512→    }
   513→    
   514→    DLogTagDebug(kBLEKeyPredictTag, @"最终的距离是:%.2f",currentDistance);
   515→    _currentDistance = currentDistance;
   516→    DLogTagDebug(kBLEKeyPredictTag,[self printPower]);
   517→    [self pushInQueue:currentDistance];
   518→#ifdef XPPollingSDK_Test_Mode
   519→    printf("%s", [[NSString stringWithFormat:@"走完定位，最终的距离是:%.2f",currentDistance] cStringUsingEncoding:NSUTF8StringEncoding]);
   520→#endif  //XPPollingSDK_Test_Mode
   521→    [self postLocationResult:communicateDistances outCarDistances:outCarDistances];
   522→}
   523→
   524→- (float)getRssiDistanceByName:(const string &)name distancesArray:(std::vector<on_time_distance> &)distancesArray {
   525→    float suitDistance = 0;
   526→    for (int i = 0; i<distancesArray.size(); i++) {
   527→        on_time_distance &onTimeDistance = distancesArray[i];
   528→        if (onTimeDistance.name.compare(name) == 0) {
   529→            suitDistance = onTimeDistance.distance;
   530→            break;
   531→        }
   532→    }
   533→    return suitDistance;
   534→}
   535→
   536→- (ble_config_info *)findMatchedBleConfig:(const string &)name {
   537→    ble_config_info *matchedConfig = NULL;
   538→    for (int i = 0; i < bleConfigs.size(); i++) {
   539→        ble_config_info &configInfo = bleConfigs[i];
   540→        if (configInfo.name.compare(name) == 0) {
   541→            matchedConfig = &configInfo;
   542→            break;
   543→        }
   544→    }
   545→    return matchedConfig;
   546→}
   547→
   548→- (void)stasticsCurrentDistanceCount:(float)distance {
   549→    short count = decisionPower.size();
   550→    for (int i = 0;i<count;i++) {
   551→        decision_power &power = decisionPower[i];
   552→        decision_distance_config &decisionConfig = decisionDistances[i];
   553→        if (power.distance >= distance) {
   554→            power.lessCount += 1;
   555→            power.moreCount -= 1;
   556→            if (power.lessCount >= decisionConfig.lessPower) {
   557→                power.lessCount = decisionConfig.lessPower;
   558→                power.moreCount = 0;
   559→            }
   560→        } else {
   561→            power.moreCount += 1;
   562→            power.lessCount -= 1;
   563→            if (power.moreCount >= decisionConfig.morePower) {
   564→                power.lessCount = 0;
   565→                power.moreCount = decisionConfig.morePower;
   566→            }
   567→        }
   568→    }
