//
//  XPPollingOptPredictModel.m
//  XPCarControlCore
//
//  Created by huzy2 on 2023/3/20.
//

#import "PLXPPollingOptPredictModel.h"
#include <math.h>

static const int PLIN_CAR_POWER_COUNT = 5;
static const int PLDISTANCE_POWER_COUNT = 10;
static const int PLHISTORY_CREDICT_COUNT = 3;

static const float PLINVAILD_DISTANCE = -1;
static const float PLIN_CAR_DISTANCE = 0.05;
static const int PLLESS_IN_CAR_POWER = 1;
static const int PLMORE_IN_CAR_POWER = 6;
static const float PLMUST_UNLOCK_DISTANCE = 1;
static const int PLLESS_MUST_UNLOCK_POWER = 1;
static const int PLMORE_MUST_UNLOCK_POWER = 1;
static const float PLSAFE_DISTANCE = 1.9;
static const int PLLESS_SAFE_POWER = 1;
static const int PLMORE_SAFE_POWER = 1;
static const float PLDEFAULT_UNLOCK_DISTANCE = 4;
static const int PLLESS_UNLOCK_POWER = 2;
static const int PLMORE_UNLOCK_POWER = 2;
static const float PLDEFAULT_LOCK_DISTANCE = 7;
static const int PLLESS_LOCK_POWER = 2;
static const int PLMORE_LOCK_POWER = 2;
static const float PLFAR_AWAY_DISTANCE = 10;
static const int PLLESS_FAR_AWAY_POWER = 3;
static const int PLMORE_FAR_AWAY_POWER = 3;
static const float PLWELCOME_DISTANCE = 20;
static const int PLLESS_WELCOME_POWER = 3;
static const int PLMORE_WELOCME_POWER = 3;
static const float PLCONNECT_DISTANCE = 1000;
static const int PLLESS_CONNECT_POWER = 3;
static const int PLMORE_CONNECT_POWER = 3;

static const float PLREVEAL_RATE = 0.95;
static const float PLHISTORY_RATE = 0.5;
static const float PLCURRENT_RATE = 0.5;
static const float PLHISTORY_INVAILD_RATE = 1.3;

struct decision_power {
    float distance = 0;
    int lessCount = 1;
    int moreCount = 1;
};

typedef struct decision_distance_config {
    float distance = 0;
    int lessPower = 1;
    int morePower = 1;
    PLBLEKeyDistanceLevel lessLevel = PLBLEKeyDistanceLevelInitCircle;
    PLBLEKeyDistanceLevel moreLevel = PLBLEKeyDistanceLevelInitCircle;
};


@implementation PLXPPollingOptPredictModel
{
    std::vector<decision_distance_config> decisionDistances;
    std::deque<float> distancePower;
    std::vector<decision_power> decisionPower;

    std::vector<ble_config_info> bleConfigs;
    std::deque<int> resultWindow;
    float _currentDistance;
}

- (id)initWithPredictConfig:(PLPredictConfig *)predictConfig pollingConfigs:(NSArray<NSDictionary *> *)otaConfigs {
    if (self = [super initWithPredictConfig:predictConfig pollingConfigs:otaConfigs]) {
        self.predictConfig = predictConfig;
        _currentDistance = PLINVAILD_DISTANCE;
        decision_distance_config inCarConfig;
        inCarConfig.distance = PLIN_CAR_DISTANCE;
        inCarConfig.lessPower = PLLESS_IN_CAR_POWER;
        inCarConfig.morePower = PLMORE_IN_CAR_POWER;
        inCarConfig.lessLevel = PLBLEKeyDistanceLevelInCar;
        inCarConfig.moreLevel = PLBLEKeyDistanceLevelOneMeterCircle;
        decisionDistances.push_back(inCarConfig);
        decision_distance_config mustUnlockConfig;
        mustUnlockConfig.distance = PLMUST_UNLOCK_DISTANCE;
        mustUnlockConfig.lessPower = PLLESS_MUST_UNLOCK_POWER;
        mustUnlockConfig.morePower = PLMORE_MUST_UNLOCK_POWER;
        mustUnlockConfig.lessLevel = PLBLEKeyDistanceLevelOneMeterCircle;
        mustUnlockConfig.moreLevel = PLBLEKeyDistanceLevelUnlockCircle;
        decisionDistances.push_back(mustUnlockConfig);
        decision_distance_config safeDistanceConfig;
        safeDistanceConfig.distance = PLSAFE_DISTANCE;
        safeDistanceConfig.lessPower = PLLESS_SAFE_POWER;
        safeDistanceConfig.morePower = PLMORE_SAFE_POWER;
        safeDistanceConfig.lessLevel = PLBLEKeyDistanceLevelUnlockCircle;
        safeDistanceConfig.moreLevel = PLBLEKeyDistanceLevelUnlockCircle;
        decisionDistances.push_back(safeDistanceConfig);
        decision_distance_config unlockConfig;
        unlockConfig.distance = _bussinessDistance.unlockDistance;
        unlockConfig.lessPower = PLLESS_UNLOCK_POWER;
        unlockConfig.morePower = PLMORE_UNLOCK_POWER;
        unlockConfig.lessLevel = PLBLEKeyDistanceLevelUnlockCircle;
        unlockConfig.moreLevel = PLBLEKeyDistanceLevelEnableCircle;
        decisionDistances.push_back(unlockConfig);
        decision_distance_config enableConfig;
        unlockConfig.distance = _bussinessDistance.enableDistance;
        unlockConfig.lessPower = PLLESS_UNLOCK_POWER;
        unlockConfig.morePower = PLMORE_UNLOCK_POWER;
        unlockConfig.lessLevel = PLBLEKeyDistanceLevelEnableCircle;
        unlockConfig.moreLevel = PLBLEKeyDistanceLevelBuffCircle;
        decisionDistances.push_back(unlockConfig);
        decision_distance_config lockConfig;
        lockConfig.distance = _bussinessDistance.lockDistance;
        lockConfig.lessPower = PLLESS_LOCK_POWER;
        lockConfig.morePower = PLMORE_LOCK_POWER;
        lockConfig.lessLevel = PLBLEKeyDistanceLevelBuffCircle;
        lockConfig.moreLevel = PLBLEKeyDistanceLevelLockCircle;
        decisionDistances.push_back(lockConfig);
        decision_distance_config farAwayConfig;
        farAwayConfig.distance = PLFAR_AWAY_DISTANCE;
        farAwayConfig.lessPower = PLLESS_FAR_AWAY_POWER;
        farAwayConfig.morePower = PLMORE_FAR_AWAY_POWER;
        farAwayConfig.lessLevel = PLBLEKeyDistanceLevelLockCircle;
        farAwayConfig.moreLevel = PLBLEKeyDistanceLevelWelcomeCircle;
        decisionDistances.push_back(farAwayConfig);
        decision_distance_config welcomeConfig;
        welcomeConfig.distance = PLWELCOME_DISTANCE;
        welcomeConfig.lessPower = PLLESS_WELCOME_POWER;
        welcomeConfig.morePower = PLMORE_WELOCME_POWER;
        welcomeConfig.lessLevel = PLBLEKeyDistanceLevelWelcomeCircle;
        welcomeConfig.moreLevel = PLBLEKeyDistanceLevelConnectCircle;
        decisionDistances.push_back(welcomeConfig);
        decision_distance_config connectConfig;
        connectConfig.distance = PLCONNECT_DISTANCE;
        connectConfig.lessPower = PLLESS_CONNECT_POWER;
        connectConfig.morePower = PLMORE_CONNECT_POWER;
        connectConfig.lessLevel = PLBLEKeyDistanceLevelConnectCircle;
        connectConfig.moreLevel = PLBLEKeyDistanceLevelInitCircle;
        decisionDistances.push_back(connectConfig);
        std::sort(decisionDistances.begin(), decisionDistances.end(), plCompareOptDistanceFuction);
        for (int i = 0; i < decisionDistances.size(); i++) {
            decision_power power;
            power.distance = decisionDistances[i].distance;
            power.lessCount = 0;
            power.moreCount = 0;
            decisionPower.push_back(power);
        }
    }
    return self;
}

- (void)updateOTAPollingConfigs:(NSArray<NSDictionary *> *)pollingConfigs {
    [super updateOTAPollingConfigs:pollingConfigs];
    bleConfigs.clear();
    for (int i = 0;i<pollingConfigs.count;i++) {
        ble_config_info power;
        power.txPower = [[pollingConfigs[i] valueForKey:@"txPower"] shortValue];
        power.a = [[pollingConfigs[i] valueForKey:@"a"] floatValue];
        power.b = [[pollingConfigs[i] valueForKey:@"b"] floatValue];
        power.c = [[pollingConfigs[i] valueForKey:@"c"] floatValue];
        power.name = [[pollingConfigs[i] valueForKey:@"name"] UTF8String];
        power.is_communicate = [[pollingConfigs[i] valueForKey:@"is_communicate"] boolValue];
        bleConfigs.push_back(power);
    }
    [self makeBleLocationConfig];
}

- (void)modelInit {
    [super modelInit];
    if (model == NULL) {
        model = new PLXPPollingPredictInterfaceOpt();
        model->init();
    }
    [self makeBleLocationConfig];
}

- (void)reset {
    [super reset];
    distancePower.clear();
    if (model == NULL) {
        return;
    }
    model->reset();
    for (int i = 0; i < decisionPower.size(); i++) {
        decision_power &power = decisionPower[i];
        power.lessCount = 0;
        power.moreCount = 0;
    }
    _currentDistance = PLINVAILD_DISTANCE;
}

- (PLBLEKeyDistanceLevel)location {
    if (model == NULL) {
        return PLBLEKeyDistanceLevelInitCircle;
    }
    if (decisionPower.size() > 0) {
        decision_distance_config *suitDistanceConfig = NULL;
        int suitIndex = -1;
        for (int i = 0;i<decisionPower.size();i++) {
            decision_power &power = decisionPower[i];
            decision_distance_config &decisionConfig = decisionDistances[i];
            if (power.lessCount >= decisionConfig.lessPower) {
                suitIndex = i;
                suitDistanceConfig = &decisionConfig;
                break;
            }
        }
        DLogTagDebug(kBLEKeyPredictTag, @"找到了满足的index:%d",suitIndex);
        if (suitIndex != -1) {
            if (self.distanceLevel == PLBLEKeyDistanceLevelInitCircle || suitIndex == 0) {
                self.distanceLevel = suitDistanceConfig->lessLevel;
            } else {
                decision_distance_config *moreDistanceConfig = NULL;
                for (int i = suitIndex-1;i>=0;i--) {
                    decision_power &power = decisionPower[i];
                    decision_distance_config &decisionConfig = decisionDistances[i];
                    if (power.moreCount >= decisionConfig.morePower) {
                        DLogTagDebug(kBLEKeyPredictTag, @"找到了满足的配置:%f,%d",decisionConfig.distance,decisionConfig.morePower);
                        moreDistanceConfig = &decisionConfig;
                        break;
                    }
                }
                if (suitDistanceConfig != NULL && moreDistanceConfig != NULL) {
                    if (self.distanceLevel <= moreDistanceConfig->moreLevel) {
                        self.distanceLevel = moreDistanceConfig->moreLevel;
                    } else {
                        self.distanceLevel = suitDistanceConfig->lessLevel;
                    }
                }

            }
        }
    }
    return self.distanceLevel;
}

- (void)postLocationResult:(vector<on_time_distance> &)communicateDistances outCarDistances:(vector<on_time_distance> &)outCarDistances {
    PLBLEKeyDistanceLevel distanceLevel = [self location];
    self.distanceLevel = distanceLevel;
    float distance = distancePower.back();
    NSMutableDictionary *locationResult = [NSMutableDictionary dictionary];
    locationResult[@"distanceLevel"] = @(distanceLevel);
    locationResult[@"distance"] = @(distance);
    NSMutableArray *tempArray = [NSMutableArray array];
    for (int i = 0; i<communicateDistances.size(); i++) {
        on_time_distance &distance = communicateDistances[i];
        NSMutableDictionary *dict = [NSMutableDictionary dictionary];
        dict[@"name"] = [NSString stringWithUTF8String:distance.name.c_str()];
        dict[@"distance"] = @(distance.distance);
        dict[@"rssi"] = @(distance.rssi);
        [tempArray addObject:dict];
    }
    for (int i = 0; i<outCarDistances.size(); i++) {
        on_time_distance &distance = outCarDistances[i];
        NSMutableDictionary *dict = [NSMutableDictionary dictionary];
        dict[@"name"] = [NSString stringWithUTF8String:distance.name.c_str()];
        dict[@"distance"] = @(distance.distance);
        dict[@"rssi"] = @(distance.rssi);
        [tempArray addObject:dict];
    }
    locationResult[@"distanceArray"] = [tempArray copy];
    [[NSNotificationCenter defaultCenter] postNotificationName:kBleLocationPredictSuccess object:nil userInfo:locationResult];
}

- (NSString *)printPower {
    NSString *string = @"powerCount:";
    for (int i = 0; i<decisionPower.size(); i++) {
        decision_power &power = decisionPower[i];
        string = [string stringByAppendingString:[@(power.distance) stringValue]];
        string = [string stringByAppendingString:[NSString stringWithFormat:@":lessCount=%d,",power.lessCount]];
        string = [string stringByAppendingString:[NSString stringWithFormat:@"moreCount=%d",power.moreCount]];
        string = [string stringByAppendingString:@" "];
    }
    string = [string stringByAppendingString:@"]"];
    return string;
}

- (NSString *)printDistance:(std::vector<float>)distance {
    NSString *string = @"距离 [";
    for (int i = 0; i<distance.size(); i++) {
        float sub = distance[i];
        string = [string stringByAppendingString:[@(sub) stringValue]];
        string = [string stringByAppendingString:@" "];
    }
    string = [string stringByAppendingString:@"]"];
    return string;
}

- (NSString *)printDebugDistance:(std::vector<float>)distance {
    NSString *string = @"debug距离 [";
    for (int i = 0; i<distance.size(); i++) {
        float sub = distance[i];
        string = [string stringByAppendingString:[@(sub) stringValue]];
        string = [string stringByAppendingString:@" "];
    }
    string = [string stringByAppendingString:@"]"];
    return string;
}

- (float)getLineWeight:(int)position size:(int)size {
    int sum = [self getSum:size];
    if (sum == 0) {
        return 0;
    } else {
        return (float)position/sum;
    }
}

- (int)getSum:(int)size {
    if (size == 0) {
        return 0;
    }
    int sum = 0;
    for(int i=1;i<= size;i++){
        sum += i;
    }
    return sum;
}

- (void)pushInQueue:(float)distance {
    distancePower.push_back(distance);
    if (distancePower.size() > PLDISTANCE_POWER_COUNT) {
        distancePower.pop_front();
    }
}

- (std::vector<float>)getLastCredictDistance {
    std::vector<float> vaildDistance;
    int historyCount = (int)distancePower.size();
    int lastCount = 0;
    if (historyCount <= PLHISTORY_CREDICT_COUNT) {
        lastCount = historyCount;
    } else {
        lastCount = PLHISTORY_CREDICT_COUNT;
    }
    for (int i = historyCount - lastCount; i < historyCount; i++) {
        vaildDistance.push_back(distancePower[i]);
    }
    return vaildDistance;;
}

- (NSString *)printHistoryData {
    NSString *string = @"历史数据 [";
    for (int i = 0; i<distancePower.size(); i++) {
        float sub = distancePower[i];
        string = [string stringByAppendingString:[NSString stringWithFormat:@"%.2f",sub]];
        string = [string stringByAppendingString:@" "];
    }
    string = [string stringByAppendingString:@"]"];
    return string;
}

- (PLBLELocationResult)bleKeyIsInCar {
    DLogTagDebug(kBLEKeyLocationTag, @"APP定位距离:%f, startDistance:%f", _currentDistance, self.startDistance);
    if (_currentDistance == PLINVAILD_DISTANCE) {
        return PLBLELocationResultNone;
    } else if (_currentDistance <= self.startDistance){
        return PLBLELocationResultInCar;
    } else {
        return PLBLELocationResultOutCar;
    }
}


#pragma mark — PredictModelProtocol
- (void)makeBleLocationConfig {
    if (model == NULL) {
        DLogTagError(kBLEKeyPredictTag, @"model为空");
        return;
    }
    if (bleConfigs.size() == 0) {
        DLogTagError(kBLEKeyPredictTag, @"标定参数不能为空，使用默认值");
        return;
    }
    PLXPPollingPredictInterfaceOpt *interfaceModel = (PLXPPollingPredictInterfaceOpt *)model;
    interfaceModel->setBleConfigs(bleConfigs);
}

- (NSDictionary *)getMinDistance:(std::vector<float>)distances {
    float min_distance = 1000;
    int index = -1;
    for (int i = 0; i<distances.size(); i++) {
        float b = distances[i];
        if (b == PLINVAILD_DISTANCE) {
            continue;
        }
        if (b < min_distance) {
            min_distance = b;
            index = i;
        }
    }
    if (index == -1) {
        min_distance = PLINVAILD_DISTANCE;
    }

    return @{@"minDistance":@(min_distance),@"index":@(index)};
}

- (NSDictionary *)getMaxDistance:(std::vector<float>)distances {
    float max_distance = -1000;
    int index = -1;
    for (int i = 0; i<distances.size(); i++) {
        float b = distances[i];
        if (b == PLINVAILD_DISTANCE) {
            continue;
        }
        if (b > max_distance) {
            max_distance = b;
            index = i;
        }
    }
    if (index == -1) {
        max_distance = PLINVAILD_DISTANCE;
    }

    return @{@"maxDistance":@(max_distance),@"index":@(index)};
}

- (void)predictWithRssi:(std::vector<ble_rssi> &)rssiV {
    if (model == NULL) {
#ifdef XPPollingSDK_Test_Mode
        printf("%s", [@"PLXPPollingOptPredictModel model为空，不执行定位" cStringUsingEncoding:NSUTF8StringEncoding]);
#endif  //XPPollingSDK_Test_Mode
        DLogTagWarn(kBLEKeyPredictTag, @"model为空，不执行定位");
        return;
    }
    std::vector<std::vector<float>> input;
    PLXPPollingPredictInterfaceOpt *predictModel = (PLXPPollingPredictInterfaceOpt *)model;
    predictModel->preprocess(rssiV, input);
    if (input.empty()) {
        DLogTagDebug(kBLEKeyPredictTag, @"model为空，不执行定位");
        return;
    }
    DLogTagDebug(@"input", @"%@",[self printInput:input]);
    std::vector<on_time_distance> output;
    predictModel->inference(output);
    if (output.empty() || output.size() == 0) {
#ifdef XPPollingSDK_Test_Mode
        printf("%s", [@"predictClass fail!" cStringUsingEncoding:NSUTF8StringEncoding]);
#endif  //XPPollingSDK_Test_Mode
        DLogTagError(kBLEKeyPredictTag, @"predictClass fail!");
        return;
    }

    std::vector<on_time_distance> outCarDistances;
    std::vector<on_time_distance> communicateDistances;
    float isCommunicateDistance = 0;
    float inCarDistance = 0;
    for(int i = 0;i<output.size();i++) {
        on_time_distance &distance = output[i];
        if (distance.is_communicate) {
            if (distance.distance != PLINVAILD_DISTANCE) {
                isCommunicateDistance += distance.distance;
                communicateDistances.push_back(distance);
            }
        } else {
            if (distance.distance != PLINVAILD_DISTANCE) {
                outCarDistances.push_back(distance);
            }
        }
    }

    isCommunicateDistance = isCommunicateDistance / communicateDistances.size();

    float currentDistance = 0;
    if (isCommunicateDistance <= PLMUST_UNLOCK_DISTANCE/2.0) {
        currentDistance = isCommunicateDistance;
    } else {
        std::sort(outCarDistances.begin(), outCarDistances.end(), plCompareOnTimeDistanceFunction);
        if (outCarDistances.size() > 0) {
            float outDistance = outCarDistances.front().distance;
            float reveatDistance = (outDistance + isCommunicateDistance)/2;
            if (reveatDistance < PLSAFE_DISTANCE) {
                currentDistance = reveatDistance;
            } else {
                if (outDistance < isCommunicateDistance) {
                    currentDistance = outDistance * self.predictConfig.slaveStrongerRate + isCommunicateDistance * (1-self.predictConfig.slaveStrongerRate);
                } else {
                    if (isCommunicateDistance <= _bussinessDistance.unlockDistance) {
                        if (outDistance > isCommunicateDistance * 2) {
                            currentDistance = isCommunicateDistance * PLREVEAL_RATE + outDistance * (1-PLREVEAL_RATE);
                        } else {
                            currentDistance = isCommunicateDistance * self.predictConfig.mainStrongerRate + outDistance * (1-self.predictConfig.mainStrongerRate);
                        }
                    } else {
                        currentDistance = isCommunicateDistance * self.predictConfig.mainStrongerRate + outDistance * (1-self.predictConfig.mainStrongerRate);
                    }
                }
            }
        } else {
            currentDistance = isCommunicateDistance;
        }
    }
    DLogTagDebug(kBLEKeyPredictTag, @"加权后的距离是:%.2f",currentDistance);

    if (distancePower.size() > 0) {
        std::vector<float> lastCredictDistance = [self getLastCredictDistance];
        int credictCount = (int)lastCredictDistance.size();
        float historyDistance = 0;
        for (int i = 0;i<credictCount;i++) {
            if (lastCredictDistance[i] != PLINVAILD_DISTANCE) {
                historyDistance += lastCredictDistance[i] * PLHISTORY_RATE * [self getLineWeight:i+1 size:credictCount];
            }
        }
        currentDistance = currentDistance * PLCURRENT_RATE + historyDistance;
    }

    for (int i = 0;i<decisionDistances.size();i++) {
        if (currentDistance <= decisionDistances[i].distance) {
            [self stasticsCurrentDistanceCount:decisionDistances[i].distance];
            break;
        }
    }

    DLogTagDebug(kBLEKeyPredictTag, @"最终的距离是:%.2f",currentDistance);
    _currentDistance = currentDistance;
    DLogTagDebug(kBLEKeyPredictTag,[self printPower]);
    [self pushInQueue:currentDistance];
#ifdef XPPollingSDK_Test_Mode
    printf("%s", [[NSString stringWithFormat:@"走完定位，最终的距离是:%.2f",currentDistance] cStringUsingEncoding:NSUTF8StringEncoding]);
#endif  //XPPollingSDK_Test_Mode
    [self postLocationResult:communicateDistances outCarDistances:outCarDistances];
}

- (float)getRssiDistanceByName:(const string &)name distancesArray:(std::vector<on_time_distance> &)distancesArray {
    float suitDistance = 0;
    for (int i = 0; i<distancesArray.size(); i++) {
        on_time_distance &onTimeDistance = distancesArray[i];
        if (onTimeDistance.name.compare(name) == 0) {
            suitDistance = onTimeDistance.distance;
            break;
        }
    }
    return suitDistance;
}

- (ble_config_info *)findMatchedBleConfig:(const string &)name {
    ble_config_info *matchedConfig = NULL;
    for (int i = 0; i < bleConfigs.size(); i++) {
        ble_config_info &configInfo = bleConfigs[i];
        if (configInfo.name.compare(name) == 0) {
            matchedConfig = &configInfo;
            break;
        }
    }
    return matchedConfig;
}

- (void)stasticsCurrentDistanceCount:(float)distance {
    short count = decisionPower.size();
    for (int i = 0;i<count;i++) {
        decision_power &power = decisionPower[i];
        decision_distance_config &decisionConfig = decisionDistances[i];
        if (power.distance >= distance) {
            power.lessCount += 1;
            power.moreCount -= 1;
            if (power.lessCount >= decisionConfig.lessPower) {
                power.lessCount = decisionConfig.lessPower;
                power.moreCount = 0;
            }
        } else {
            power.moreCount += 1;
            power.lessCount -= 1;
            if (power.moreCount >= decisionConfig.morePower) {
                power.lessCount = 0;
                power.moreCount = decisionConfig.morePower;
            }
        }
    }
}

- (void)pushInResultQueue:(int)result {
    resultWindow.push_back(result);
    if (resultWindow.size() > 5) {
        resultWindow.pop_front();
    }
}

bool plCompareOnTimeDistanceFunction(on_time_distance &i,on_time_distance &j) {
    return i.distance < j.distance;
}

bool plCompareOptDistanceFuction(decision_distance_config &i,decision_distance_config &j) {
    return i.distance < j.distance;
}




